// Hash computes the SHA256 hash of the file at path.
func Hash(path string) ([]byte, error) {
	f, err := os.Open(path)
	if err != nil {
		return nil, fmt.Errorf("Hash: %w", err)
	}
	defer f.Close() // read-only; Close error is not actionable
	h := sha256.New()
	if _, err := io.Copy(h, f); err != nil {
		return nil, fmt.Errorf("Hash: %w", err)
	}
	return h.Sum(nil), nil
}
